import React, { useState } from 'react';
import axios from 'axios';
import '../assets/styles/Skype.css'; // Presupunem că stilurile pentru Skype se vor afla aici

const Skype = ({ onClose }) => {
  const [errorMessage, setErrorMessage] = useState('');

  const handleOpenSkype = () => {
    axios.post('/shortcuts/skype/open-skype/')
      .then(response => {
        console.log(response.data.message || 'Skype opened successfully');
        setErrorMessage(''); // Resetăm orice eroare
      })
      .catch(error => {
        console.error('There was an error opening Skype!', error);
        setErrorMessage('There was an error opening Skype.');
      });
  };

  const handleCloseSkype = () => {
    axios.post('/shortcuts/skype/close-skype/')
      .then(response => {
        console.log(response.data.message || 'Skype closed successfully');
        setErrorMessage('');
        if (onClose) onClose(); // Dacă avem o funcție pentru a închide componenta, o apelăm
      })
      .catch(error => {
        console.error('There was an error closing Skype!', error);
        setErrorMessage('There was an error closing Skype.');
      });
  };

  return (
    <div className="skype-container">
      <h1 className="title">Skype</h1>
      <div className="button-container">
        <button onClick={handleOpenSkype} className="button open-skype-button">
          Open Skype
        </button>
        <button onClick={handleCloseSkype} className="button close-skype-button">
          Close Skype
        </button>
      </div>

      {errorMessage && (
        <div className="error-message">
          {errorMessage}
        </div>
      )}
    </div>
  );
};

export default Skype;
